#include <stdio.h>
#include <string.h>
#include <stdlib.h>
#include <math.h>
#include <iostream>
#include <string>
#include "kmeans.h"

#ifndef FLT_MAX
#define FLT_MAX 3.40282347e+38f
#endif

#define BLOCK_SIZE 256
#define BLOCK_SIZE2 256

int platform_id_inuse = 0;            
int device_id_inuse = 0;              

float *d_feature = nullptr;
float *d_feature_swap = nullptr;
float *d_cluster = nullptr;
int   *d_membership = nullptr;

int   *membership_OCL = nullptr;

int initialize()
{
    // No explicit initialization needed for CUDA here
    return 0;
}

int shutdown()
{
    if(d_feature) cudaFree(d_feature);
    if(d_feature_swap) cudaFree(d_feature_swap);
    if(d_cluster) cudaFree(d_cluster);
    if(d_membership) cudaFree(d_membership);
    if(membership_OCL) free(membership_OCL);

    d_feature = nullptr;
    d_feature_swap = nullptr;
    d_cluster = nullptr;
    d_membership = nullptr;
    membership_OCL = nullptr;

    return 0;
}

int allocate(int n_points, int n_features, int n_clusters, float **feature)
{
    cudaError_t err;

    if(initialize()) return -1;

    err = cudaMalloc((void**)&d_feature, n_points * n_features * sizeof(float));
    if(err != cudaSuccess) { printf("ERROR: cudaMalloc d_feature failed\n"); return -1; }
    err = cudaMalloc((void**)&d_feature_swap, n_points * n_features * sizeof(float));
    if(err != cudaSuccess) { printf("ERROR: cudaMalloc d_feature_swap failed\n"); return -1; }
    err = cudaMalloc((void**)&d_cluster, n_clusters * n_features * sizeof(float));
    if(err != cudaSuccess) { printf("ERROR: cudaMalloc d_cluster failed\n"); return -1; }
    err = cudaMalloc((void**)&d_membership, n_points * sizeof(int));
    if(err != cudaSuccess) { printf("ERROR: cudaMalloc d_membership failed\n"); return -1; }

    err = cudaMemcpy(d_feature, feature[0], n_points * n_features * sizeof(float), cudaMemcpyHostToDevice);
    if(err != cudaSuccess) { printf("ERROR: cudaMemcpy d_feature failed\n"); return -1; }

    // Launch kernel to swap feature layout
    int threads = BLOCK_SIZE;
    int blocks = (n_points + threads - 1) / threads;
    kmeans_swap<<<blocks, threads>>>(d_feature, d_feature_swap, n_points, n_features);
    cudaDeviceSynchronize();

    membership_OCL = (int*) malloc(n_points * sizeof(int));
    if(!membership_OCL) { printf("ERROR: malloc membership_OCL failed\n"); return -1; }

    return 0;
}

void deallocateMemory()
{
    shutdown();
}

extern "C" __global__ void kmeans_kernel_c(float  *feature,   
			  float  *clusters,
			  int    *membership,
			    int     npoints,
				int     nclusters,
				int     nfeatures,
				int		offset,
				int		size
			  );

extern "C" __global__ void kmeans_swap(float  *feature,   
			float  *feature_swap,
			int     npoints,
			int     nfeatures
);

int	kmeansOCL(float **feature,    
           int     n_features,
           int     n_points,
           int     n_clusters,
           int    *membership,
		   float **clusters,
		   int     *new_centers_len,
           float  **new_centers)	
{

	int delta = 0;
	int i, j;
	cudaError_t err;

	int threads = BLOCK_SIZE2;
	int blocks = (n_points + threads - 1) / threads;

	err = cudaMemcpy(d_cluster, clusters[0], n_clusters * n_features * sizeof(float), cudaMemcpyHostToDevice);
	if(err != cudaSuccess) { printf("ERROR: cudaMemcpy d_cluster failed\n"); return -1; }

	int size = 0; int offset = 0;
	kmeans_kernel_c<<<blocks, threads>>>(d_feature_swap, d_cluster, d_membership, n_points, n_clusters, n_features, offset, size);
	cudaDeviceSynchronize();

	err = cudaMemcpy(membership_OCL, d_membership, n_points * sizeof(int), cudaMemcpyDeviceToHost);
	if(err != cudaSuccess) { printf("ERROR: cudaMemcpy membership_OCL failed\n"); return -1; }

	delta = 0;
	for (i = 0; i < n_points; i++)
	{
		int cluster_id = membership_OCL[i];
		new_centers_len[cluster_id]++;
		if (membership_OCL[i] != membership[i])
		{
			delta++;
			membership[i] = membership_OCL[i];
		}
		for (j = 0; j < n_features; j++)
		{
			new_centers[cluster_id][j] += feature[i][j];
		}
	}

	return delta;
}

int main( int argc, char** argv) 
{
	printf("WG size of kernel_swap = %d, WG size of kernel_kmeans = %d \n", BLOCK_SIZE, BLOCK_SIZE2);

	setup(argc, argv);
	shutdown();

	return 0;
}
